-- 02_importar_facturas_y_distribuciones.sql
-- Importa 106 facturas nuevas (con totales agregados) + 324 distribuciones
-- desde Movimientos_caja.xlsx (324 filas, 193 PDFs únicos en Excel).
--
-- BD actual: 99 facturas limpias (de las cuales 87 coinciden con Excel, 12 no).
-- Esperado tras ejecutar: 99 + 106 = 205 facturas y 324 distribuciones.
-- Las 12 facturas BD-only NO se tocan (datos historicos, no borrar nunca).
--
-- Idempotente: ON CONFLICT por nombre_archivo, DELETE previo en distribuciones.
BEGIN;

-- Asegurar UNIQUE en facturas.nombre_archivo
DO $a$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'facturas_nombre_archivo_key') THEN
    ALTER TABLE facturas ADD CONSTRAINT facturas_nombre_archivo_key UNIQUE (nombre_archivo);
  END IF;
END $a$;

-- Limpiar distribuciones previas (idempotente)
DELETE FROM factura_distribuciones;

-- ====== 106 INSERTs en facturas ======

-- ====== 324 INSERTs en factura_distribuciones ======

-- ====== VERIFICACIÓN ======
DO $a$
DECLARE v_facturas INT; v_distrib INT;
BEGIN
  SELECT COUNT(*) INTO v_facturas FROM facturas;
  SELECT COUNT(*) INTO v_distrib FROM factura_distribuciones;
  RAISE NOTICE 'Facturas: %', v_facturas;
  RAISE NOTICE 'Distribuciones: %', v_distrib;
  IF v_facturas <> 205 THEN RAISE EXCEPTION 'FAIL esperaba 205 facturas, got %', v_facturas; END IF;
  IF v_distrib <> 324  THEN RAISE EXCEPTION 'FAIL esperaba 324 distribuciones, got %', v_distrib; END IF;
  RAISE NOTICE 'OK 205 facturas, 324 distribuciones';
END $a$;

COMMIT;